package main

import (
  "context"
  "log"

  rewrite "github.com/rewritetoday/golang"
)

func main() {
  client, err := rewrite.New("rw_your_api_key")
  if err != nil { log.Fatal(err) }

  webhookID := "748395130237498700"

  _, err = client.Webhooks.Update(context.Background(), webhookID, rewrite.UpdateWebhookOptions{
    RESTPatchUpdateWebhookBody: rewrite.RESTPatchUpdateWebhookBody{
      Endpoint: "https://example.com/webhooks/rewrite-v2",
      Events: []rewrite.WebhookEventType{
        rewrite.WebhookEventTypeSMSDelivered,
        rewrite.WebhookEventTypeSMSFailed,
      },
      Status: rewrite.WebhookStatusActive,
    },
  })
  if err != nil { log.Fatal(err) }
}

import com.rewritetoday.sdk.Rewrite;
import com.rewritetoday.sdk.models.webhooks.UpdateWebhookOptions;
import java.util.List;

public class Main {
  public static void main(String[] args) throws Exception {
    var rewrite = new Rewrite(System.getenv("REWRITE_API_KEY"));

    var webhookId = "748395130237498700";

    var webhook = rewrite.webhooks().update(
      webhookId,
      UpdateWebhookOptions.builder()
        .endpoint("https://example.com/webhooks/rewrite-v2")
        .events(List.of("sms.delivered", "sms.failed"))
        .status("ACTIVE")
        .build()
    );

    System.out.println(webhook);
  }
}

